class Solution:
    def maxNonDecreasingLength(self, nums1: List[int], nums2: List[int]) -> int:
        n = len(nums1)
        max_len = 1
        curr_len1 = 1
        curr_len2 = 1

        for i in range(1, n):
            new_len1 = 1
            new_len2 = 1

            if nums1[i] >= nums1[i - 1]:
                new_len1 = curr_len1 + 1
            if nums2[i] >= nums2[i - 1]:
                new_len2 = curr_len2 + 1

            if nums1[i] >= nums2[i - 1]:
                new_len1 = max(new_len1, curr_len2 + 1)
            if nums2[i] >= nums1[i - 1]:
                new_len2 = max(new_len2, curr_len1 + 1)

            max_len = max(max_len, new_len1, new_len2)
            curr_len1, curr_len2 = new_len1, new_len2

        return max_len
